const ToolCallRenderer = memo(function ToolCallRenderer({ block }: { block: ToolCallBlock }): React.ReactElement {
  const [expanded, setExpanded] = useState(block.status === 'running')

  // Tool-specific header info
  const toolIcon: Record<string, string> = {
    bash: '▶',
    read: '📄',
    edit: '✏️',
    write: '📝',
  }
  const icon = toolIcon[block.toolName] ?? '🔧'

  // Build header summary based on tool type
  let headerSummary = ''
  switch (block.toolName) {
    case 'bash':
      headerSummary = block.args.command
        ? String(block.args.command).length > 80
          ? String(block.args.command).substring(0, 80) + '...'
          : String(block.args.command)
        : ''
      break
    case 'read':
      headerSummary = block.args.path ? String(block.args.path) : ''
      break
    case 'edit':
      headerSummary = block.args.path ? String(block.args.path) : ''
      break
    case 'write':
      headerSummary = block.args.path ? String(block.args.path) : ''
      break
    default:
      headerSummary = ''
  }

  // Status indicator
  const statusEl = (() => {
    switch (block.status) {
      case 'running':
        return (
          <svg className="h-3.5 w-3.5 animate-spin text-yellow-400" viewBox="0 0 24 24" fill="none">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
          </svg>
        )
      case 'completed':
        return <span className="text-green-400 text-xs">✓</span>
      case 'error':
        return <span className="text-red-400 text-xs">✗</span>
      case 'pending':
        return <span className="text-gray-400 text-xs">⋯</span>
    }
  })()

  // Auto-expand when running
  if (block.status === 'running' && !expanded) {
    setExpanded(true)
  }

  return (
    <div className="my-2 overflow-hidden rounded-lg border border-gray-700">
      {/* Dark header bar */}
      <button
        onClick={() => setExpanded(!expanded)}
        className="flex w-full items-center gap-2 bg-gray-800 px-3 py-1.5 text-left hover:bg-gray-750 transition-colors"
      >
        <span className="text-xs">{icon}</span>
        <span className="font-mono text-xs font-medium text-gray-200">{block.toolName}</span>
        {headerSummary && (
          <span className="flex-1 truncate font-mono text-xs text-gray-400">{headerSummary}</span>
        )}
        {!headerSummary && <span className="flex-1" />}
        {statusEl}
        <svg
          className={`h-3 w-3 text-gray-500 transition-transform ${expanded ? 'rotate-90' : ''}`}
          fill="currentColor"
          viewBox="0 0 20 20"
        >
          <path fillRule="evenodd" d="M7.293 14.707a1 1 0 010-1.414L10.586 10 7.293 6.707a1 1 0 011.414-1.414l4 4a1 1 0 010 1.414l-4 4a1 1 0 01-1.414 0z" clipRule="evenodd" />
        </svg>
      </button>
      {/* Expandable args section */}
      {expanded && (
        <div className="border-t border-gray-700 bg-gray-900 px-3 py-2">
          <pre className="overflow-x-auto text-xs text-gray-300">
            {JSON.stringify(block.args, null, 2)}
          </pre>
        </div>
      )}
    </div>
  )
})

