const COLLAPSE_THRESHOLD = 15

function ToolResultRenderer({ block }: { block: ToolResultBlock }): React.ReactElement {
  const textItems = block.content.filter((c): c is TextBlock => c.type === 'text')
  const fullText = textItems.map((c) => c.content).join('\n')
  const lines = fullText.split('\n')
  const lineCount = lines.length
  const isLong = lineCount > COLLAPSE_THRESHOLD
  const [collapsed, setCollapsed] = useState(isLong)

  // Check if parent tool is bash (heuristic: look for terminal-style content)
  const isBashOutput = fullText.length > 0 && (fullText.includes('$ ') || fullText.includes('drwx') || fullText.includes('-rw-'))

  const displayText = collapsed && isLong
    ? lines.slice(0, COLLAPSE_THRESHOLD).join('\n')
    : fullText

  return (
    <div className={`my-1 overflow-hidden rounded-lg border ${isBashOutput ? 'border-gray-700' : 'border-gray-200'}`}>
      {/* Header */}
      <div className={`flex items-center justify-between px-3 py-1 ${isBashOutput ? 'bg-gray-800' : 'bg-gray-100'}`}>
        <span className={`text-xs font-medium ${isBashOutput ? 'text-gray-400' : 'text-gray-500'}`}>
          Output
          {lineCount > 1 && <span className="ml-1 font-normal">({lineCount} lines)</span>}
        </span>
        {isLong && (
          <button
            onClick={() => setCollapsed(!collapsed)}
            className={`text-xs hover:underline ${isBashOutput ? 'text-blue-400' : 'text-blue-500'}`}
          >
            {collapsed ? `Show all ${lineCount} lines` : 'Collapse'}
          </button>
        )}
      </div>
      {/* Content */}
      <div className={`${isBashOutput ? 'bg-gray-900' : 'bg-gray-50'} px-3 py-2 overflow-x-auto`}>
        <pre className={`whitespace-pre-wrap text-xs font-mono ${isBashOutput ? 'text-green-400' : 'text-gray-600'}`}>
          {displayText}
        </pre>
        {collapsed && isLong && (
          <div className="mt-1 text-center">
            <button
              onClick={() => setCollapsed(false)}
              className={`text-xs hover:underline ${isBashOutput ? 'text-blue-400' : 'text-blue-500'}`}
            >
              ▸ Show all {lineCount} lines
            </button>
          </div>
