      </div>
      {/* Non-text content (images, html) */}
      {block.content.map((child, i) => {
        if (child.type === 'image') {
          return <ImageBlockRenderer key={`img-${i}`} block={child as ImageBlock} />
        }
        if (child.type === 'html') {
