/**
 * Build a mapping from block index to parent tool name.
 * For tool_result blocks, find the most recent tool_call before it.
 */
function buildToolNameMap(blocks: ContentBlock[]): Map<number, string> {
  const map = new Map<number, string>()
  let lastToolName: string | undefined
  for (let i = 0; i < blocks.length; i++) {
    const block = blocks[i]
    if (block.type === 'tool_call') {
      lastToolName = block.toolName
    } else if (block.type === 'tool_result' && lastToolName) {
      map.set(i, lastToolName)
    } else if (block.type === 'text') {
      // Text blocks after a tool_call are likely tool output, keep context
      // But don't assign tool name to regular text
    }
  }
  return map
}

