function ToolResultRenderer({ block }: { block: ToolResultBlock }): React.ReactElement {
  const textItems = block.content.filter((c): c is TextBlock => c.type === 'text')
  const fullText = textItems.map((c) => c.content).join('\n')
  const lines = fullText.split('\n')
  const lineCount = lines.length
  const isLong = lineCount > COLLAPSE_THRESHOLD
  const [collapsed, setCollapsed] = useState(isLong)

  const hasTextContent = fullText.trim().length > 0

  const displayText = collapsed && isLong
    ? lines.slice(0, COLLAPSE_THRESHOLD).join('\n')
    : fullText

  // If no content at all, don't render
  if (!hasTextContent && !block.content.some((c) => c.type === 'image' || c.type === 'html')) {
    return <></>
  }

  return (
    <div className="my-1 overflow-hidden rounded-lg border border-gray-200">
      {hasTextContent && (<>
      {/* Header */}
      <div className="flex items-center justify-between bg-gray-50 px-3 py-1">
        <span className="text-xs font-medium text-gray-500">
          Output
          {lineCount > 1 && <span className="ml-1 font-normal">({lineCount} lines)</span>}
        </span>
        {isLong && (
          <button
            onClick={() => setCollapsed(!collapsed)}
            className="text-xs text-blue-500 hover:underline"
          >
            {collapsed ? `Show all ${lineCount} lines` : 'Collapse'}
          </button>
        )}
      </div>
      {/* Content */}
      <div className="bg-white px-3 py-2 overflow-x-auto">
        <pre className="whitespace-pre-wrap text-xs font-mono text-gray-600">
          {displayText}
        </pre>
        {collapsed && isLong && (
          <div className="mt-1 text-center">
            <button
              onClick={() => setCollapsed(false)}
              className="text-xs text-blue-500 hover:underline"
            >
              ▸ Show all {lineCount} lines
            </button>
          </div>
        )}
      </div>
      </>)}
      {/* Non-text content (images, html) */}
      {block.content.map((child, i) => {
