          return <ImageBlockRenderer key={`img-${i}`} block={child as ImageBlock} />
        }
        if (child.type === 'html') {
          return <HtmlBlockRenderer key={`html-${i}`} block={child as HtmlBlock} />
        }
        return null
      })}
    </div>
  )
}

