// Consecutive tool_call pairs are grouped into a shared card.
const elements: React.ReactElement[] = []
const skipIndices = new Set<number>()
let i = 0

while (i < msg.blocks.length) {
  if (skipIndices.has(i)) { i++; continue }
  const block = msg.blocks[i]

  if (block.type === 'tool_call') {
    // Collect consecutive tool_call (+ paired tool_result) blocks
    const group: { block: ToolCallBlock; result?: ToolResultBlock }[] = []

    while (i < msg.blocks.length && (msg.blocks[i].type === 'tool_call' || msg.blocks[i].type === 'tool_result')) {
      if (skipIndices.has(i)) { i++; continue }
      const cur = msg.blocks[i]
      if (cur.type === 'tool_call') {
        const next = msg.blocks[i + 1]
        const result = (next?.type === 'tool_result') ? next as ToolResultBlock : undefined
        if (result) { skipIndices.add(i + 1); i++ }
        group.push({ block: cur, result })
        i++
      } else if (cur.type === 'tool_result') {
        // Orphan tool_result within the group
        group.push({ block: cur as unknown as ToolCallBlock, result: cur as ToolResultBlock })
        i++
      } else {
        break
      }
    }

    // Render group in a shared card
    elements.push(
      <div key={`tg-${elements.length}`} className="my-1 overflow-hidden rounded-lg border border-gray-200">
        {group.map((item, gi) => (
          <ToolCallRenderer key={`tc-${gi}`} block={item.block} result={item.result} />
        ))}
      </div>
    )
  } else if (block.type === 'tool_result') {
    // Orphan tool_result
    elements.push(
      <OrphanToolResultRenderer key={`tr-${i}`} block={block} />
    )
    i++
  } else {
    elements.push(
      <ContentBlockRenderer
        key={`cb-${i}`}
        block={block}
        messageId={msg.id}
        blockIndex={i}
        isStreamingBlock={isStreaming && streamingMessageId === msg.id && block.type === 'text'}
        annotatingTarget={annotatingTarget}
        onEnterAnnotation={onEnterAnnotation}
        onExitAnnotation={onExitAnnotation}
        onSendFeedback={onSendFeedback}
      />
    )
    i++
  }
}

return <div className="space-y-2">{elements}</div>

