// Collect all tool_call/tool_result pairs from the message into one card.
// Other blocks render normally in order.
const toolGroup: { block: ToolCallBlock; result?: ToolResultBlock }[] = []
const toolResultIndices = new Set<number>()

// First pass: find all tool_call + tool_result pairs
for (let j = 0; j < msg.blocks.length; j++) {
  const block = msg.blocks[j]
  if (block.type === 'tool_call') {
    const next = msg.blocks[j + 1]
    const result = (next?.type === 'tool_result') ? next as ToolResultBlock : undefined
    if (result) { toolResultIndices.add(j + 1) }
    toolGroup.push({ block, result })
  }
}

// Second pass: render non-tool blocks, insert one tool card before the first tool block
const elements: React.ReactElement[] = []
let toolCardInserted = false

for (let j = 0; j < msg.blocks.length; j++) {
  const block = msg.blocks[j]

  // Skip tool_call and its paired tool_result
  if (block.type === 'tool_call') {
    if (!toolCardInserted) {
      toolCardInserted = true
      elements.push(
        <div key={`tg`} className="my-1 overflow-hidden rounded-lg border border-gray-200">
          {toolGroup.map((item, gi) => (
            <ToolCallRenderer key={`tc-${gi}`} block={item.block} result={item.result} />
          ))}
        </div>
      )
    }
    continue
  }
  if (toolResultIndices.has(j)) continue

  // Orphan tool_result (no preceding tool_call)
  if (block.type === 'tool_result') {
    elements.push(
      <OrphanToolResultRenderer key={`tr-${j}`} block={block} />
    )
    continue
  }

  elements.push(
    <ContentBlockRenderer
      key={`cb-${j}`}
      block={block}
      messageId={msg.id}
      blockIndex={j}
      isStreamingBlock={isStreaming && streamingMessageId === msg.id && block.type === 'text'}
      annotatingTarget={annotatingTarget}
      onEnterAnnotation={onEnterAnnotation}
      onExitAnnotation={onExitAnnotation}
      onSendFeedback={onSendFeedback}
    />
  )
}

